// Function to calculate the distance between two points
double distance(double x1, double y1, double x2, double y2) {
    return sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
}

// Function to check if three points are collinear
int areCollinear(double x1, double y1, double x2, double y2, double x3, double y3) {
    double d1 = distance(x1, y1, x2, y2);
    double d2 = distance(x2, y2, x3, y3);
    double d3 = distance(x3, y3, x1, y1);
    return fabs(d1 + d2 - d3) < 1e-9;
}

// Function to calculate the area of a triangle using Heron's formula
double heronsFormula(double a, double b, double c) {
    double s = (a + b + c) / 2.0;
    return sqrt(s * (s - a) * (s - b) * (s - c));
}

#include <stdio.h>
#include <stdlib.h>
#include <time.h>

int main(void) {
    srand(time(NULL));
    int numbers[5], guessed[5] = {0}, score = 0;

    // Generate 5 unique random numbers between 1 and 10
    for (int i = 0; i < 5; i++) {
        int num;
        do {
            num = rand() % 10 + 1;
        } while (num == 0 || guessed[num - 1]);
        numbers[i] = num;
        guessed[num - 1] = 1;
    }

    // Game loop
    for (int i = 0; i < 5; i++) {
        printf("Numbers: ");
        for (int j = 0; j < 5; j++) {
            if (guessed[j]) {
                printf("%d ", numbers[j]);
            } else {
                printf("* ");
            }
        }
        printf("\nPick position (1-5): ");
        int pos;
        scanf("%d", &pos);

        printf("Guess (E for even, O for odd): ");
        char guess;
        scanf(" %c", &guess);

        if ((numbers[pos - 1] % 2 == 0 && guess == 'E') || 
            (numbers[pos - 1] % 2 != 0 && guess == 'O')) {
            printf("Correct!\n");
            score += 5;
        } else {
            printf("Incorrect.\n");
        }

        guessed[pos - 1] = 1;
    }

    // Display final score
    printf("Final Score: %d\n", score);

    return 0;
}

